import{_ as a,C as o,o as s,c as l,E as r,w as i,a as n,a0 as d}from"./chunks/framework.CkNTPv-z.js";const w=JSON.parse('{"title":"Moving to the Netherlands","description":"Immigration pathways and relocation guide for transgender people moving to the Netherlands","frontmatter":{"layout":"doc","title":"Moving to the Netherlands","description":"Immigration pathways and relocation guide for transgender people moving to the Netherlands"},"headers":[],"relativePath":"europe/netherlands/moving-there.md","filePath":"europe/netherlands/moving-there.md","lastUpdated":null}'),h={name:"europe/netherlands/moving-there.md"};function g(c,e,u,m,p,f){const t=o("Badge");return s(),l("div",null,[r(t,{variant:"green"},{default:i(()=>[...e[0]||(e[0]=[n("EU Free Movement",-1)])]),_:1}),r(t,{variant:"yellow"},{default:i(()=>[...e[1]||(e[1]=[n("High Cost of Living",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="moving-to-the-netherlands" tabindex="-1">Moving to the Netherlands <a class="header-anchor" href="#moving-to-the-netherlands" aria-label="Permalink to &quot;Moving to the Netherlands&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eu-eea-swiss-citizens" tabindex="-1">EU/EEA/Swiss Citizens <a class="header-anchor" href="#eu-eea-swiss-citizens" aria-label="Permalink to &quot;EU/EEA/Swiss Citizens&quot;">​</a></h3><p>The Netherlands grants free movement to EU/EEA/Swiss citizens. Registration is required for stays over four months.</p><h3 id="non-eu-citizens" tabindex="-1">Non-EU Citizens <a class="header-anchor" href="#non-eu-citizens" aria-label="Permalink to &quot;Non-EU Citizens&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Description</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Highly Skilled Migrant (Kennismigrant)</td><td>For skilled workers with job offer</td><td>Job offer, salary threshold (€5,008/month 30+ / €3,672/month under 30)</td><td>Up to 5 years</td></tr><tr><td>EU Blue Card</td><td>For highly qualified professionals</td><td>Degree + salary threshold (approx. €65,000/year)</td><td>Up to 4 years</td></tr><tr><td>DAFT (Dutch American Friendship Treaty)</td><td>For US citizens starting a business</td><td>€4,500 investment in Dutch business</td><td>2 years, renewable</td></tr><tr><td>Orientation Year (Zoekjaar)</td><td>For recent graduates from top 200 universities</td><td>Degree from qualifying institution</td><td>1 year</td></tr><tr><td>Work Visa (GVVA)</td><td>For employment</td><td>Combined work/residence permit</td><td>1 year, renewable</td></tr><tr><td>Family Reunification</td><td>For family of residents</td><td>Relationship proof, sufficient income</td><td>1 year, renewable</td></tr></tbody></table><h2 id="key-relocation-steps" tabindex="-1">Key Relocation Steps <a class="header-anchor" href="#key-relocation-steps" aria-label="Permalink to &quot;Key Relocation Steps&quot;">​</a></h2><ol><li><strong>Find housing</strong> — Housing crisis is severe; start searching months in advance</li><li><strong>Register with the municipality (BRP)</strong> — Required within 5 days of arrival (for long stays)</li><li><strong>Apply for a residence permit</strong> — Non-EU citizens apply through the IND before arrival</li><li><strong>Register for health insurance</strong> — Mandatory within 4 months (€100-150/month)</li><li><strong>Open a bank account</strong> — BSN (citizen service number) required first</li><li><strong>Get a BSN</strong> — Registered at the municipality</li><li><strong>Learn Dutch</strong> — Essential for integration and citizenship (A2 level for permanent residence, B1 for citizenship)</li></ol><h2 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h2><p>High, especially in major cities:</p><ul><li>Rent (1-bedroom): €1,200-2,000/month (Amsterdam); €900-1,400 (other cities)</li><li>Groceries: €350-550/month</li><li>Public transport: €100-150/month pass</li><li>Health insurance: €100-150/month (mandatory)</li><li>Healthcare deductible (eigen risico): €385/year</li></ul><h2 id="trans-specific-relocation-tips" tabindex="-1">Trans-Specific Relocation Tips <a class="header-anchor" href="#trans-specific-relocation-tips" aria-label="Permalink to &quot;Trans-Specific Relocation Tips&quot;">​</a></h2><ul><li><strong>Trans-friendly healthcare</strong> is concentrated in UMC cities (Amsterdam, Groningen)</li><li><strong>English is widely spoken</strong> — nearly all Dutch people speak fluent English</li><li><strong>Bring medical records translated into Dutch or English</strong></li><li><strong>Carry at least 3 months of HRT medication</strong> with a doctor&#39;s letter</li><li><strong>Register with a GP (huisarts)</strong> on arrival; they are the gateway to specialist care</li><li><strong>Join Transgender Network Nederland</strong> for community and advocacy</li><li><strong>Amsterdam is the most trans-friendly city</strong> but also the most expensive</li><li><strong>Consider Groningen</strong> for shorter healthcare wait times and lower rent</li></ul><h2 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h2><ul><li><strong>Official language</strong>: Dutch</li><li><strong>English</strong> — Widely spoken, over 90% fluency</li><li><strong>Dutch</strong> required for permanent residence (A2) and citizenship (B1)</li><li>Free language courses are available through municipalities</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>IND (Immigration and Naturalisation Service)</strong> — <a href="https://ind.nl/" target="_blank" rel="noreferrer">ind.nl</a></li><li><strong>Rijksoverheid</strong> — Relocation information: <a href="https://www.rijksoverheid.nl/" target="_blank" rel="noreferrer">rijksoverheid.nl</a></li><li><strong>Transgender Network Nederland</strong> — <a href="https://www.transgendernetwerk.nl/" target="_blank" rel="noreferrer">transgendernetwerk.nl</a></li><li><strong>COC Nederland</strong> — LGBTQ+ support: <a href="https://www.coc.nl/" target="_blank" rel="noreferrer">coc.nl</a></li><li><strong>UWV</strong> — Employment services: <a href="https://www.uwv.nl/" target="_blank" rel="noreferrer">uwv.nl</a></li></ul>',17))])}const v=a(h,[["render",g]]);export{w as __pageData,v as default};
